const initFlashMessages=()=>{const e=document.getElementById("flash-messages-data"),n=document.getElementById("flash-announcer");if(!e)return;JSON.parse(e.dataset.messages||"[]").forEach(({category:s,message:t})=>{console.log(`[${s.toUpperCase()}] ${t}`),n&&(n.textContent=`${s}: ${t}`)})};document.addEventListener("DOMContentLoaded",initFlashMessages);
